$blogDir = 'c:\Users\HOLA\OneDrive\Escritorio\juristam-web\blog'
$utf8noBOM = New-Object System.Text.UTF8Encoding $false
$updated = 0; $skipped = 0; $notFound = 0

function Find-ArrayClose($str, $startPos) {
    $openPos = $str.IndexOf('[', $startPos)
    if ($openPos -lt 0) { return -1 }
    $depth = 0; $inStr = $false; $esc = $false
    $bsc = [int][char]92; $dqc = [int][char]34
    for ($i = $openPos; $i -lt $str.Length; $i++) {
        $ci = [int][char]$str[$i]
        if ($esc) { $esc = $false; continue }
        if ($ci -eq $bsc -and $inStr) { $esc = $true; continue }
        if ($ci -eq $dqc) { $inStr = !$inStr; continue }
        if (-not $inStr) {
            if ($str[$i] -eq '[') { $depth++ }
            elseif ($str[$i] -eq ']') { $depth--; if ($depth -eq 0) { return $i } }
        }
    }
    return -1
}

function Add-FaqData($filename, $jsonAdd, $htmlAdd) {
    $path = Join-Path $blogDir $filename
    if (-not (Test-Path $path)) { $script:notFound++; Write-Host "NOT FOUND: $filename"; return }
    $c = [System.IO.File]::ReadAllText($path, [System.Text.Encoding]::UTF8)
    $marker = $jsonAdd.Substring(0,[Math]::Min(50,$jsonAdd.Length))
    if ($c.IndexOf($marker) -ge 0) { $script:skipped++; Write-Host "SKIP: $filename"; return }
    $tag = '<script type="application/ld+json">'
    $si = $c.IndexOf($tag); $ei = $c.IndexOf('</script>', $si)
    if ($si -ge 0) {
        $jb = $c.Substring($si+$tag.Length, $ei-$si-$tag.Length)
        $fp = $jb.IndexOf('"FAQPage"')
        if ($fp -ge 0) {
            $mp = $jb.IndexOf('"mainEntity"', $fp)
            $cl = Find-ArrayClose $jb $mp
            if ($cl -ge 0) {
                $abs = $si+$tag.Length+$cl
                $c = $c.Substring(0,$abs) + ',' + $jsonAdd + $c.Substring($abs)
            }
        }
    }
    $ld = $c.LastIndexOf('</details>')
    if ($ld -ge 0) {
        $cd = $c.IndexOf('</div>', $ld+10)
        if ($cd -ge 0) { $c = $c.Substring(0,$cd) + $htmlAdd + "`n" + $c.Substring($cd) }
    }
    [System.IO.File]::WriteAllText($path, $c, $utf8noBOM)
    $script:updated++; Write-Host "OK: $filename"
}

Add-FaqData '15-anos-como-se-cuentan-prescripcion-ecuador.html' `
'{"@type":"Question","name":"¿Los 15 años corren aunque no viva en el terreno?","acceptedAnswer":{"@type":"Answer","text":"No necesariamente. Si delegaste el cuidado y sigues ejerciendo actos de dueño, el tiempo puede seguir corriendo. Si lo abandonaste completamente, puede interrumpirse. Escríbenos: 0994859814."}},{"@type":"Question","name":"¿Qué pasa si el terreno estuvo a nombre de otra persona todo ese tiempo?","acceptedAnswer":{"@type":"Answer","text":"Que otro tenga el título no impide la prescripción. Lo que cuenta es quién ejerció posesión real, no quién aparece en el registro. Escríbenos: 0994859814."}},{"@type":"Question","name":"¿Cuánto tarda el juicio una vez que completo los 15 años?","acceptedAnswer":{"@type":"Answer","text":"Entre 1 y 3 años dependiendo del juzgado y si hay oposición. No es automático — necesitas un proceso judicial para que el juez declare la prescripción. Escríbenos: 0994859814."}},{"@type":"Question","name":"¿Una carta notarial interrumpe los 15 años?","acceptedAnswer":{"@type":"Answer","text":"No. Solo la demanda judicial presentada y notificada correctamente interrumpe el plazo. Una carta notarial no tiene ese efecto legal en Ecuador. Escríbenos: 0994859814."}}' `
'<details><summary>¿Los 15 años corren aunque no viva en el terreno?</summary><p class="faq-answer">No necesariamente. Si delegaste el cuidado y sigues ejerciendo actos de dueño, el tiempo puede seguir corriendo. Si lo abandonaste completamente, puede interrumpirse. Escríbenos: 0994859814.</p></details>
<details><summary>¿Qué pasa si el terreno estuvo a nombre de otra persona todo ese tiempo?</summary><p class="faq-answer">Que otro tenga el título no impide la prescripción. Lo que cuenta es quién ejerció posesión real, no quién aparece en el registro. Escríbenos: 0994859814.</p></details>
<details><summary>¿Cuánto tarda el juicio una vez que completo los 15 años?</summary><p class="faq-answer">Entre 1 y 3 años dependiendo del juzgado y si hay oposición. No es automático — necesitas un proceso judicial para que el juez declare la prescripción. Escríbenos: 0994859814.</p></details>
<details><summary>¿Una carta notarial interrumpe los 15 años?</summary><p class="faq-answer">No. Solo la demanda judicial presentada y notificada correctamente interrumpe el plazo. Una carta notarial no tiene ese efecto legal en Ecuador. Escríbenos: 0994859814.</p></details>'

Add-FaqData 'accion-reivindicatoria-terreno-ecuador.html' `
'{"@type":"Question","name":"¿Puedo iniciar la acción reivindicatoria sin escritura pública?","acceptedAnswer":{"@type":"Answer","text":"No. Exige que el demandante sea el propietario con título inscrito. Sin escritura, la acción correcta sería otra. Escríbenos: 0994859814."}},{"@type":"Question","name":"¿Qué pasa si el ocupante lleva más de 15 años en el terreno?","acceptedAnswer":{"@type":"Answer","text":"Puede oponer la prescripción adquisitiva y ganar aunque tú tengas escritura. Por eso actuar a tiempo es crítico. Escríbenos: 0994859814."}},{"@type":"Question","name":"¿Cuánto tarda una acción reivindicatoria en Ecuador?","acceptedAnswer":{"@type":"Answer","text":"Entre 1 y 2 años en promedio, dependiendo de si el ocupante opone excepciones y del juzgado. Escríbenos: 0994859814."}},{"@type":"Question","name":"¿Sirve contra un familiar que ocupa el terreno?","acceptedAnswer":{"@type":"Answer","text":"Sí procede legalmente, pero entre familiares puede haber reconocimiento implícito de dominio que complica el caso. Escríbenos: 0994859814."}}' `
'<details><summary>¿Puedo iniciar la acción reivindicatoria sin escritura pública?</summary><p class="faq-answer">No. Exige que el demandante sea el propietario con título inscrito. Sin escritura, la acción correcta sería otra. Escríbenos: 0994859814.</p></details>
<details><summary>¿Qué pasa si el ocupante lleva más de 15 años en el terreno?</summary><p class="faq-answer">Puede oponer la prescripción adquisitiva y ganar aunque tú tengas escritura. Por eso actuar a tiempo es crítico. Escríbenos: 0994859814.</p></details>
<details><summary>¿Cuánto tarda una acción reivindicatoria en Ecuador?</summary><p class="faq-answer">Entre 1 y 2 años en promedio, dependiendo de si el ocupante opone excepciones y del juzgado. Escríbenos: 0994859814.</p></details>
<details><summary>¿Sirve contra un familiar que ocupa el terreno?</summary><p class="faq-answer">Sí procede legalmente, pero entre familiares puede haber reconocimiento implícito de dominio que complica el caso. Escríbenos: 0994859814.</p></details>'

Add-FaqData 'animo-de-dueno-posesion-ecuador.html' `
